/// <summary>
/// Class <c>ETGSPAINPurchAgreementFulfillment</c> extends <c>ETGSPAINSalesPurchAgreementFulfillment</c>
/// for managing Purchase Agreement Fulfillment in the ETGSPAIN model.
/// </summary>
class ETGSPAINPurchAgreementFulfillment extends ETGSPAINSalesPurchAgreementFulfillment
{
}

Method.Source:
/// <summary>
/// Returns the class description.
/// </summary>
/// <returns><c>ClassDescription</c></returns>
static ClassDescription description()
{
    return "@ETGSPAINLabels:ETGSPAINPurchAgreementFollowUpTmp";
}

/// <summary>
/// Enables or disables the data sources based on the type of agreement (purchase or sales).
/// </summary>
/// <param name="_enable">Boolean value indicating if the data sources should be enabled.</param>
protected void enableDataSources()
{
    if (CompanyInfo::find().ETGSpanishCompany == NoYes::Yes)
    {
        QueryBuildDataSource qbds;

        qbds = query.dataSourceTable(tableNum(PurchAgreementHeader));
        qbds.enabled(true);
        qbds.findRange(fieldNum(PurchAgreementHeader, VendAccount)).status(RangeStatus::Open);
        qbds.findRange(fieldNum(PurchAgreementHeader, PurchNumberSequence)).status(RangeStatus::Open);

        qbds = query.dataSourceTable(tableNum(SalesAgreementHeader));
        qbds.enabled(false);
        qbds.findRange(fieldNum(SalesAgreementHeader, CustAccount)).status(RangeStatus::Hidden);
        qbds.findRange(fieldNum(SalesAgreementHeader, SalesNumberSequence)).status(RangeStatus::Hidden);
    }
}

/// <summary>
/// Fills the follow-up temporary table with data from the purchase agreement header.
/// </summary>
/// <param name="_etgSPAINSalesPurchAgreementFollowUpTmp">Temporary table to be filled.</param>
/// <param name="_agreementHeader">The agreement header record.</param>
/// <returns>The updated <c>ETGSPAINSalesPurchAgreementFollowUpTmp</c>.</returns>
protected ETGSPAINSalesPurchAgreementFollowUpTmp fillSalesPurchAgreementHeader(ETGSPAINSalesPurchAgreementFollowUpTmp _etgSPAINSalesPurchAgreementFollowUpTmp, AgreementHeader _agreementHeader)
{

    if (CompanyInfo::find().ETGSpanishCompany == NoYes::Yes)
    {
        PurchAgreementHeader purchAgreementHeader = PurchAgreementHeader::find(_agreementHeader.RecId);

        _etgSPAINSalesPurchAgreementFollowUpTmp.AgreementId  = purchAgreementHeader.PurchNumberSequence;
        _etgSPAINSalesPurchAgreementFollowUpTmp.CustVendName = strfmt("%1 - %2", purchAgreementHeader.VendAccount, purchAgreementHeader.vendName());
        _etgSPAINSalesPurchAgreementFollowUpTmp.CustVendAC   = purchAgreementHeader.VendAccount;
    }

    return _etgSPAINSalesPurchAgreementFollowUpTmp;
}

/// <summary>
/// Constructs and returns an instance of the <c>ETGSPAINPurchAgreementFulfillment</c> class.
/// </summary>
/// <returns>Instance of <c>ETGSPAINPurchAgreementFulfillment</c>.</returns>
public static ETGSPAINPurchAgreementFulfillment construct()
{
    return new ETGSPAINPurchAgreementFulfillment();
}

/// <summary>
/// Main method of the class. Generates and returns the temporary table <c>ETGSPAINSalesPurchAgreementFollowUpTmp</c>.
/// </summary>
/// <returns>The <c>ETGSPAINSalesPurchAgreementFollowUpTmp</c> filled with the agreement follow-up data.</returns>
public static ETGSPAINSalesPurchAgreementFollowUpTmp generateETGSPAINSalesPurchAgreementFollowUpTmp()
{
    ETGSPAINPurchAgreementFulfillment etgSPAINPurchAgreementFulfillment;

    if (CompanyInfo::find().ETGSpanishCompany == NoYes::Yes)
    {
        etgSPAINPurchAgreementFulfillment = ETGSPAINPurchAgreementFulfillment::construct(); 

        if (etgSPAINPurchAgreementFulfillment.prompt())
        {
            etgSPAINPurchAgreementFulfillment.run();
        }
    }

    return etgSPAINPurchAgreementFulfillment.getETGSPAINSalesPurchAgreementFollowUpTmp();
}
